vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

    // sample previous uFrame
    ret = texture( sampler_main, vUv ).xyz;
    ret=mix(ret,ret.zxy,0.2); //channel shiftin'

    //add dither
    vec2 d_uv=vUvOriginal*uTexSize.xy*texsize_noise_lq.zw+rand_frame.xy;
    ret+=(texture(sampler_noise_lq,d_uv).xyz-0.5)/256*2;

